// VULNERABLE CODE:
String query = "SELECT * FROM users WHERE username='" 
    + userInput + "' AND password='" + passInput + "'";

// EXPLOIT: Enter username: admin' OR '1'='1' --
// Query becomes:
// SELECT * FROM users WHERE username='admin' OR '1'='1' --' AND password=''
// The -- comments out the password check!
// Result: Logs in as admin without knowing the password

// DETECTION: Enter a single quote ' in username field
// If you see: SQL error, unmatched quote, or database error -> LIKELY VULNERABLE

// FIX:
PreparedStatement ps = conn.prepareStatement(
    "SELECT * FROM users WHERE username=? AND password=?");
ps.setString(1, userInput);
ps.setString(2, passInput);

// VULNERABLE CODE:
