import java.sql.*;

public class SQLiDemo {
    // VULNERABLE login method
    static String vulnerableLogin(String user, String pass) {
        String query = "SELECT * FROM users WHERE username='" + user
            + "' AND password='" + pass + "'";
        System.out.println("Query: " + query);
        // Simulate: would execute against database
        if (query.contains("OR '1'='1'") || query.contains("OR 1=1")) {
            return "LOGIN SUCCESS (SQL injection!): Admin access granted";
        }
        if (user.equals("admin") && pass.equals("adminPassword")) {
            return "LOGIN SUCCESS: Welcome admin";
        }
        return "LOGIN FAILED: Invalid credentials";
    }

    public static void main(String[] args) {
        System.out.println("=== SQL INJECTION ASSESSMENT ===");
        System.out.println();
        System.out.println("--- Normal Login ---");
        System.out.println(vulnerableLogin("admin", "adminPassword"));
        System.out.println();
        System.out.println("--- Detection: Single Quote Test ---");
        System.out.println(vulnerableLogin("admin'", "test"));
        System.out.println("(If this causes an SQL error, injection is likely)\n");
        System.out.println("--- Exploit: Authentication Bypass ---");
        System.out.println(vulnerableLogin("admin' OR '1'='1' --", "anything"));
        System.out.println();
        System.out.println("--- Exploit: Union-based data extraction ---");
        System.out.println(vulnerableLogin("' UNION SELECT username,password FROM users --", ""));
    }
}

public class XSSDetection {
    // Simulate a vulnerable page that reflects input
    static String renderPage(String userInput) {
        return "<html><body><p>Search results for: " + userInput + "</p></body></html>";
    }

    // Secure version with encoding
    static String renderPageSecure(String userInput) {
        String encoded = userInput
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#x27;");
        return "<html><body><p>Search results for: " + encoded + "</p></body></html>";
    }

    static boolean detectsXSS(String html) {
        return html.contains("<script") || html.contains("onerror=") || html.contains("onload=");
    }

    public static void main(String[] args) {
        String[] payloads = {
            "<script>alert('XSS')</script>",
            "<img src=x onerror=alert(1)>",
            "<svg onload=alert(1)>",
            "normal search term",
            "<b>bold text</b>"
        };

        System.out.println("=== XSS DETECTION RESULTS ===");
        for (String p : payloads) {
            String html = renderPage(p);
            String htmlSafe = renderPageSecure(p);
            boolean vuln = detectsXSS(html);
            boolean safe = detectsXSS(htmlSafe);
            System.out.println("\nPayload: " + p);
            System.out.println("  Vulnerable page: " + (vuln ? "XSS DETECTED!" : "Clean"));
            System.out.println("  Secure page:     " + (safe ? "XSS DETECTED!" : "Clean"));
        }
    }
}

import java.util.regex.*;

public class CSRFCheck {
    static String checkForm(String formName, String formHtml) {
        boolean hasToken = formHtml.contains("csrf_token") || 
                          formHtml.contains("_csrf") ||
                          formHtml.contains("authenticity_token");
        boolean isPostForm = formHtml.contains("method=\"POST\"") || 
                            formHtml.contains("method='POST'");
        boolean isStateChanging = formHtml.contains("transfer") || 
                                  formHtml.contains("delete") ||
                                  formHtml.contains("update") ||
                                  formHtml.contains("password");

        StringBuilder result = new StringBuilder();
        result.append("Form: " + formName + "\n");
        result.append("  POST method: " + isPostForm + "\n");
        result.append("  State-changing: " + isStateChanging + "\n");
        result.append("  CSRF token present: " + hasToken + "\n");

        if (isStateChanging && !hasToken) {
            result.append("  VERDICT: VULNERABLE TO CSRF!\n");
        } else if (isStateChanging && hasToken) {
            result.append("  VERDICT: Protected (token found)\n");
        } else {
            result.append("  VERDICT: Low risk (not state-changing)\n");
        }
        return result.toString();
    }

    public static void main(String[] args) {
        System.out.println("=== CSRF ASSESSMENT ===");
        System.out.println(checkForm("Transfer Funds",
            "<form action='/transfer' method=\"POST\"><input name='to'><input name='amount'><button>transfer</button></form>"));
        System.out.println(checkForm("Change Password",
            "<form action='/password' method=\"POST\"><input name='csrf_token' type='hidden' value='abc123'><input name='password'><button>update</button></form>"));
        System.out.println(checkForm("Search",
            "<form action='/search' method=\"GET\"><input name='q'><button>Search</button></form>"));
    }
}

public class CmdInjectionTest {
    static String simulateCommand(String input) {
        // Simulate vulnerable command execution
        String fullCmd = "ping -c 1 " + input;
        System.out.println("  Executed: " + fullCmd);

        // Check for injection indicators
        if (input.contains(";") || input.contains("|") || input.contains("&&")
            || input.contains("`") || input.contains("$(")) {
            return "  RESULT: Additional command executed! VULNERABLE";
        }
        return "  RESULT: Normal execution";
    }

    public static void main(String[] args) {
        System.out.println("=== COMMAND INJECTION TESTING ===");
        String[] payloads = {
            "127.0.0.1",                        // Normal
            "127.0.0.1; whoami",                 // Semicolon separator
            "127.0.0.1 | cat /etc/passwd",       // Pipe
            "127.0.0.1 && ls -la",               // AND chaining
            "`whoami`",                          // Backtick substitution
            "$(cat /etc/passwd)",                 // Dollar substitution
            "127.0.0.1 || id"                     // OR chaining
        };

        for (String p : payloads) {
            System.out.println("\nPayload: " + p);
            System.out.println(simulateCommand(p));
        }
    }
}

import java.io.File;

public class PathTraversalTest {
    static final String BASE_DIR = "/var/www/uploads";

    static String testTraversal(String filename) {
        String fullPath = BASE_DIR + "/" + filename;
        // Check if path escapes base directory
        try {
            File base = new File(BASE_DIR);
            File resolved = new File(fullPath).getCanonicalFile();
            boolean escaped = !resolved.getPath().startsWith(base.getCanonicalPath());
            return String.format("  Input: %-40s -> Path: %-40s [%s]",
                filename, resolved.getPath(), escaped ? "TRAVERSAL!" : "Safe");
        } catch (Exception e) {
            return "  Error: " + e.getMessage();
        }
    }

    public static void main(String[] args) {
        System.out.println("=== PATH TRAVERSAL TESTING ===");
        System.out.println("Base directory: " + BASE_DIR + "\n");

        String[] payloads = {
            "report.pdf",                           // Normal
            "../../../etc/passwd",                   // Classic traversal
            "..%2f..%2f..%2fetc%2fpasswd",          // URL encoded
            "....//....//etc/passwd",                // Double dot bypass
            "/etc/passwd",                           // Absolute path
            "uploads/../../../etc/passwd"            // Mixed traversal
        };

        for (String p : payloads) {
            System.out.println(testTraversal(p));
        }
    }
}

import java.security.SecureRandom;
import java.util.*;

public class SessionAudit {
    static int score = 0, total = 0;

    static void check(String item, boolean pass) {
        total++;
        if (pass) score++;
        System.out.println("  [" + (pass ? "PASS" : "FAIL") + "] " + item);
    }

    public static void main(String[] args) {
        System.out.println("=== SESSION MANAGEMENT AUDIT ===");

        // Simulate session properties
        String sessionId = "kX7vR2mP9qYtN5wB3jL8pQ4rS6";
        String cookieHeader = "Set-Cookie: session=" + sessionId + "; HttpOnly; Secure; SameSite=Lax; Path=/";
        boolean changesAfterLogin = true;
        boolean expiresAfterTimeout = true;
        boolean destroyedOnLogout = false; // BUG!
        boolean idleTimeout = false; // BUG!

        System.out.println("\nSession ID Analysis:");
        check("ID length >= 16 characters", sessionId.length() >= 16);
        check("ID appears random (not sequential)", !sessionId.matches(".*\\d{4,}$"));
        check("ID not in URL (cookie-based)", true);

        System.out.println("\nCookie Security:");
        check("HttpOnly flag set", cookieHeader.contains("HttpOnly"));
        check("Secure flag set", cookieHeader.contains("Secure"));
        check("SameSite attribute set", cookieHeader.contains("SameSite"));

        System.out.println("\nSession Lifecycle:");
        check("New ID generated after login (fixation prevention)", changesAfterLogin);
        check("Absolute timeout configured", expiresAfterTimeout);
        check("Idle timeout configured", idleTimeout);
        check("Session destroyed on logout", destroyedOnLogout);

        System.out.println("\nSCORE: " + score + "/" + total);
        System.out.println("RATING: " + (score >= 9 ? "GOOD" : score >= 7 ? "FAIR" : "POOR"));
        if (!destroyedOnLogout) System.out.println("\nCRITICAL: Sessions persist after logout!");
        if (!idleTimeout) System.out.println("WARNING: No idle timeout — abandoned sessions stay active.");
    }
}

import java.util.regex.*;
import java.util.*;

public class InfoExposureScanner {
    static List<String> scan(String responseName, String content) {
        List<String> findings = new ArrayList<>();

        // Stack traces
        if (content.contains("Exception") && content.contains(".java:"))
            findings.add("Stack trace exposed (reveals language, files, line numbers)");

        // SQL errors
        if (content.contains("SQL syntax") || content.contains("mysql_") || content.contains("ORA-"))
            findings.add("SQL error exposed (reveals database type, query structure)");

        // Server version
        Pattern serverPat = Pattern.compile("Server:\\s*(Apache|nginx|Tomcat)[/\\s][\\d.]+");
        if (serverPat.matcher(content).find())
            findings.add("Server version disclosed (helps attacker target known CVEs)");

        // HTML comments with sensitive info
        Pattern commentPat = Pattern.compile("<!--.*?(password|secret|TODO|admin|key).*?-->", Pattern.CASE_INSENSITIVE);
        if (commentPat.matcher(content).find())
            findings.add("Sensitive HTML comment found");

        // Directory listing
        if (content.contains("Index of /") || content.contains("Directory listing"))
            findings.add("Directory listing enabled (CWE-548)");

        return findings;
    }

    public static void main(String[] args) {
        System.out.println("=== INFORMATION EXPOSURE SCAN ===");

        String[][] responses = {
            {"Error page", "<h1>Error</h1><pre>java.sql.SQLException: SQL syntax error\n  at DBHelper.java:42\n  at LoginServlet.java:15</pre>"},
            {"Normal page", "<html><body><h1>Welcome</h1><p>Hello user</p></body></html>"},
            {"Commented page", "<html><!-- TODO: Remove admin password: admin123 --><body>Page</body></html>"},
            {"Server header", "HTTP/1.1 200 OK\nServer: Apache/2.4.41 (Ubuntu)\nContent-Type: text/html"},
            {"Upload dir", "<html><title>Index of /uploads</title><body>Directory listing for /uploads</body></html>"}
        };

        for (String[] r : responses) {
            List<String> findings = scan(r[0], r[1]);
            System.out.println("\n" + r[0] + ": " + (findings.isEmpty() ? "CLEAN" : findings.size() + " issue(s)"));
            for (String f : findings) System.out.println("  [FOUND] " + f);
        }
    }
}

public class CIACalculator {
    static String rate(String vuln, String ciaC, String ciaI, String ciaA, String reason) {
        int score = 0;
        score += ciaC.equals("HIGH") ? 3 : ciaC.equals("MEDIUM") ? 2 : 1;
        score += ciaI.equals("HIGH") ? 3 : ciaI.equals("MEDIUM") ? 2 : 1;
        score += ciaA.equals("HIGH") ? 3 : ciaA.equals("MEDIUM") ? 2 : 1;
        String severity = score >= 8 ? "CRITICAL" : score >= 6 ? "HIGH" : score >= 4 ? "MEDIUM" : "LOW";

        return String.format("%s\n  C: %-6s  I: %-6s  A: %-6s  -> %s\n  %s\n",
            vuln, ciaC, ciaI, ciaA, severity, reason);
    }

    public static void main(String[] args) {
        System.out.println("=== CIA IMPACT ASSESSMENT ===");
        System.out.println();
        System.out.println(rate("SQL Injection (Login Bypass)",
            "HIGH", "HIGH", "HIGH",
            "Read all data, modify records, drop tables"));
        System.out.println(rate("Stored XSS (Profile Field)",
            "HIGH", "MEDIUM", "LOW",
            "Steal cookies, deface pages, no server impact"));
        System.out.println(rate("CSRF (Fund Transfer)",
            "LOW", "HIGH", "LOW",
            "Cannot read data, but modifies balances"));
        System.out.println(rate("Path Traversal (Read-only)",
            "HIGH", "LOW", "LOW",
            "Read /etc/passwd and config files, cannot modify"));
        System.out.println(rate("Missing Session Expiry",
            "MEDIUM", "MEDIUM", "LOW",
            "Extended access window if session stolen"));
        System.out.println(rate("Server Version Disclosure",
            "LOW", "LOW", "LOW",
            "Helps plan attacks but no direct impact"));
    }
}

import java.util.*;

public class AccessControlTest {
    static Map<String, String> userRoles = Map.of("admin","ADMIN", "user1","USER", "user2","USER");
    static Map<String, String> pageAccess = Map.of(
        "/dashboard", "USER", "/profile", "USER", "/admin", "ADMIN",
        "/admin/users", "ADMIN", "/reports", "ADMIN"
    );
    static Map<String, String> dataOwners = Map.of("1","user1", "2","user2", "3","admin");

    static void testVertical(String user, String page) {
        String role = userRoles.getOrDefault(user, "NONE");
        String required = pageAccess.getOrDefault(page, "ADMIN");
        boolean shouldBlock = required.equals("ADMIN") && !role.equals("ADMIN");
        // Simulate: no server-side check!
        System.out.printf("  %-8s (%-5s) -> %-15s: %s%n", user, role, page,
            shouldBlock ? "VULNERABILITY: No role check!" : "Expected access");
    }

    static void testHorizontal(String user, String dataId) {
        String owner = dataOwners.getOrDefault(dataId, "unknown");
        boolean isOwner = user.equals(owner);
        System.out.printf("  %-8s -> data %s (owner: %-8s): %s%n", user, dataId, owner,
            isOwner ? "Own data (OK)" : "OTHER USER'S DATA (IDOR!)");
    }

    public static void main(String[] args) {
        System.out.println("=== ACCESS CONTROL ASSESSMENT ===");
        System.out.println("\nVertical Escalation (user accessing admin pages):");
        testVertical("user1", "/dashboard");
        testVertical("user1", "/admin");
        testVertical("user1", "/admin/users");
        testVertical("user1", "/reports");
        testVertical("admin", "/admin");

        System.out.println("\nHorizontal Escalation (IDOR - accessing other users' data):");
        testHorizontal("user1", "1");
        testHorizontal("user1", "2");
        testHorizontal("user2", "1");
        testHorizontal("user1", "3");
    }
}

