        sb.append("VULNERABILITY #" + vulnNum + ": " + name + "\n");
        sb.append("=" .repeat(60) + "\n");
        sb.append("CWE:      " + cwe + "\n");
        sb.append("Severity: " + severity + "\n");
        sb.append("Location: " + location + "\n\n");
        sb.append("DESCRIPTION:\n  " + description + "\n\n");
        sb.append("REPRODUCTION STEPS:\n");
        for (int i = 0; i < steps.length; i++)
            sb.append("  " + (i+1) + ". " + steps[i] + "\n");
        sb.append("\nPAYLOAD: " + payload + "\n");
        sb.append("EVIDENCE: " + evidence + "\n\n");
        sb.append("CIA IMPACT:\n");
        sb.append("  Confidentiality: " + ciaC + "\n");
        sb.append("  Integrity:       " + ciaI + "\n");
        sb.append("  Availability:    " + ciaA + "\n\n");
        sb.append("REMEDIATION:\n  " + remediation + "\n");
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println(generateEntry(
            "SQL Injection in Login Form", "CWE-89", "CRITICAL",
            "/login POST endpoint, 'username' parameter",
            "The login form concatenates user input directly into a SQL query without parameterisation.",
