            "Replace string concatenation with PreparedStatement using parameterised queries."
        ));
    }
}

import java.util.*;

public class VulnScanner {
    static List<String[]> results = new ArrayList<>();

    static void testEndpoint(String endpoint, String param, String value) {
        // SQL Injection tests
        String[] sqliPayloads = {"' OR '1'='1", "1 OR 1=1", "'; DROP TABLE users; --"};
        for (String p : sqliPayloads) {
            boolean vuln = !value.contains("PreparedStatement") && (p.contains("'") || p.contains(";"));
            if (vuln) results.add(new String[]{endpoint, param, "SQL Injection", "CWE-89", p});
        }

        // XSS tests
        String[] xssPayloads = {"<script>alert(1)</script>", "<img onerror=alert(1)>"};
        for (String p : xssPayloads) {
            boolean vuln = !value.contains("encode") && p.contains("<");
            if (vuln) results.add(new String[]{endpoint, param, "XSS", "CWE-79", p});
        }

        // Command Injection tests
        String[] cmdPayloads = {"; whoami", "| ls", "&& cat /etc/passwd"};
        for (String p : cmdPayloads) {
            boolean vuln = value.contains("Runtime") && (p.contains(";") || p.contains("|"));
            if (vuln) results.add(new String[]{endpoint, param, "Command Injection", "CWE-78", p});
        }
    }

    public static void main(String[] args) {
        System.out.println("=== AUTOMATED VULNERABILITY SCAN ===");
        System.out.println("Target: Sample Web Application\n");

        testEndpoint("/login", "username", "concatenated query");
        testEndpoint("/search", "q", "reflected without encode");
        testEndpoint("/ping", "host", "Runtime.exec used");

        System.out.println("FINDINGS: " + results.size() + " potential vulnerabilities\n");
        Map<String, Integer> byCwe = new LinkedHashMap<>();
        for (String[] r : results) {
            byCwe.merge(r[3], 1, Integer::sum);
            System.out.printf("  [%s] %s in %s (%s) payload: %s%n", r[3], r[2], r[0], r[1], r[4]);
        }
        System.out.println("\nSUMMARY BY TYPE:");
        byCwe.forEach((cwe, count) -> System.out.println("  " + cwe + ": " + count + " finding(s)"));
    }
}

