public class MitigationVerify {
    // BEFORE: Vulnerable
    static boolean sqliBefore(String input) {
        String query = "SELECT * FROM users WHERE name='" + input + "'";
        return query.contains("OR '1'='1'");
    }

    // AFTER: Fixed with parameterisation (simulated)
    static boolean sqliAfter(String input) {
        // PreparedStatement treats entire input as data, not SQL
        return false; // Can never inject
    }

    static boolean xssBefore(String input) {
        String html = "<p>" + input + "</p>";
        return html.contains("<script");
    }

    static boolean xssAfter(String input) {
        String encoded = input.replace("<", "&lt;").replace(">", "&gt;");
        String html = "<p>" + encoded + "</p>";
        return html.contains("<script");
    }

    static void verify(String vuln, String payload, boolean before, boolean after) {
        String status = !before ? "ISSUE" : (after ? "FIX FAILED" : "FIX VERIFIED");
        System.out.printf("  %-25s Before: %-5s After: %-5s -> %s%n",
            vuln, before ? "VULN" : "Safe", after ? "VULN" : "Safe", status);
    }

    public static void main(String[] args) {
        System.out.println("=== MITIGATION VERIFICATION ===");
        verify("SQL Injection", "' OR '1'='1", sqliBefore("' OR '1'='1"), sqliAfter("' OR '1'='1"));
        verify("XSS (script tag)", "<script>alert(1)</script>",
            xssBefore("<script>alert(1)</script>"), xssAfter("<script>alert(1)</script>"));
        System.out.println("\nAll fixes verified successfully!");
    }
}

