public class DOMBasedXSS {
    // DOM XSS: the payload never goes to the server
    // Example: page reads URL fragment and inserts it into DOM
    // URL: /page#<script>alert(1)</script>
    // JS: document.getElementById('output').innerHTML = location.hash.substring(1);

    public static void main(String[] args) {
        String urlFragment = "<script>alert(1)</script>";
        // Simulate: innerHTML = fragment
        String rendered = "<div id='output'>" + urlFragment + "</div>";
        System.out.println("URL fragment: #" + urlFragment);
        System.out.println("Rendered: " + rendered);
        System.out.println("XSS: " + rendered.contains("<script"));
        System.out.println("\nKey difference: payload in URL fragment (#) never sent to server");
        System.out.println("Fix: Use textContent instead of innerHTML");
    }
}

