            "127.0.0.1 && cat /etc/passwd", "`whoami`", "$(id)"
        };
        for (String p : payloads) {
            System.out.println(p + " -> " + (testPayload(p) ? "INJECTION DETECTED" : "Clean"));
        }
    }
}

