import java.io.File;

public class PathTraversalDetect {
    static String testPath(String base, String input) {
        try {
            File resolved = new File(base, input).getCanonicalFile();
            boolean escaped = !resolved.getPath().startsWith(new File(base).getCanonicalPath());
            return input + " -> " + (escaped ? "TRAVERSAL!" : "Safe") + " (" + resolved.getPath() + ")";
        } catch (Exception e) { return "Error"; }
    }
    public static void main(String[] args) {
        String base = "/var/www/files";
        String[] tests = {"report.pdf", "../../../etc/passwd", "....//....//etc/passwd", "subdir/file.txt"};
        for (String t : tests) System.out.println(testPath(base, t));
    }
}

